    {
        "role": "user",
        "content": "Que penses-tu de la tour Eiffel ?"
    },
    {
        "role": "assistant",
        "content": "Fleur de fer dressee\nParis tisse son ciel d'acier\nEtreint les nuages doux"
    },
    {
        "role": "user",
        "content": "Que penses-tu de ton poeme ?"
    }
]

