probleme_logique = """
Dans une course, tu dépasses le 2ème. 
Quelle est ta position finale?
Explique ton raisonnement en une phrase.
"""

def get_content_safe(response):
    """Extrait le contenu de manière sécurisée."""
    if response is None:
        return "[Response is None]"
    if not hasattr(response, 'choices') or response.choices is None:
        return "[Response has no choices]"
    if len(response.choices) == 0:
        return "[Empty choices array]"
    if response.choices[0] is None:
        return "[First choice is None]"
    if not hasattr(response.choices[0], 'message'):
        return "[Choice has no message]"
    content = response.choices[0].message.content
    if content is None:
        return "[Content null - response truncated or reasoning-only]"
    return content.strip()

print("=== Impact du reasoning_effort ===\n")

# gpt-5-mini avec reasoning_effort via OpenRouter
for effort in ["low", "medium", "high"]:
    start = time.time()
    try:
        response = client.chat.completions.create(
            model=DEFAULT_REASONING_MODEL,
            messages=[
                {"role": "developer", "content": "Formatting re-enabled"},
                {"role": "user", "content": probleme_logique}
            ],
            max_completion_tokens=4000,  # Augmenté pour éviter content null
            extra_body={"reasoning_effort": effort}
        )
        duration = time.time() - start

        print(f"reasoning_effort='{effort}' ({duration:.2f}s):")
        print(f"  {get_content_safe(response)}")
        print()
    except Exception as e:
        print(f"reasoning_effort='{effort}': Non supporté - {str(e)[:50]}")
        break

print("[Réponse correcte: 2ème position - tu prends la place de celui que tu dépasses]")
print("\nObservation: Les 3 niveaux devraient donner la bonne réponse, mais 'high' peut fournir")
print("une explication plus détaillée. La différence est surtout visible sur des problèmes complexes.")

